#include <stdio.h>

int main() {
    int a = 10, b = 3;
    double c = 2.5;

    printf("--- Arithmetic ---\n");
    printf("Integer Div: %d / %d = %d\n", a, b, a/b);
    printf("Modulus: %d %% %d = %d\n", a, b, a%b);

    printf("\n--- Increment ---\n");
    int x = 5;
    printf("Original x: %d\n", x);
    printf("Using x++ (Post): %d\n", x++);
    printf("After x++: %d\n", x);
    printf("Using ++x (Pre): %d\n", ++x);

    printf("\n--- Mixed Expressions ---\n");
    // a (int) is promoted to double for the calculation
    double mixed = a + c; 
    printf("%d (int) + %.1f (double) = %.2f (double)\n", a, c, mixed);

    printf("\n--- Ternary ---\n");
    x > 5 ? printf("x is big\n") : printf("x is small\n");

    return 0;
}
